package batch75;

public class employee {
	int employeeId=1;
	char EmpGrade='A';
	int EmpSalary=30000;
	boolean empStatus=true;
	int WorkingDays=22;
	long pHNumber=9390646359L;
	int BonusAmount=20000;

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		
		employee N = new employee();
		
		System.out.println("Employee Id:"+N.employeeId);
		System.out.println("Employee Grade:"+N.EmpGrade);
		System.out.println("Employee Grade:"+N.EmpSalary);
		System.out.println("Employee status:"+N.empStatus);
		System.out.println("Employee WorkingDays:"+N.pHNumber);
		System.out.println("Employee Phone Number:"+N.pHNumber);
		System.out.println("Employee Bonus Amount:"+N.BonusAmount);
		
		
	}

}
